import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure user input does not exceed buffer size
        byte[] buffer = new byte[10];
        byte[] inputBytes = name.getBytes();

        if (inputBytes.length > buffer.length) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        Arrays.fill(buffer, (byte) 0); // Fill buffer with zeros before copying
        System.arraycopy(inputBytes, 0, buffer, 0, inputBytes.length);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
